+/// Benchmark: Async Loader vs Standard Read
+/// Tests SSD throughput with different loading strategies
+const std = @import("std");
+const AsyncLoader = @import("async_loader.zig").AsyncLoader;
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    // Use a model file if available, otherwise create test file
+    const test_file = blk: {
+        // Try to find a model file
+        const model_paths = [_][]const u8{
+            "/Users/steven_chong/.cache/lm-studio/models/lmstudio-community/Qwen2.5-1.5B-Instruct-GGUF/Qwen2.5-1.5B-Instruct-Q4_K_M.gguf",
+            "/tmp/async_loader_benchmark.bin",
+        };
+        for (model_paths) |path| {
+            if (std.fs.cwd().access(path, .{})) |_| {
+                break :blk path;
+            } else |_| {}
+        }
+        // Create test file
+        std.debug.print("Creating 1GB test file...\n", .{});
+        const file = try std.fs.cwd().createFile("/tmp/async_loader_benchmark.bin", .{});
+        defer file.close();
+        const chunk = [_]u8{0xAB} ** (1024 * 1024);
+        for (0..1024) |_| { // 1GB
+            try file.writeAll(&chunk);
+        }
+        break :blk "/tmp/async_loader_benchmark.bin";
+    };
+
+    std.debug.print("\n=== Async Loader Benchmark ===\n", .{});
+    std.debug.print("File: {s}\n\n", .{test_file});
+
+    // Get file size
+    const file = try std.fs.cwd().openFile(test_file, .{});
+    const stat = try file.stat();
+    file.close();
+    const size_mb = @as(f64, @floatFromInt(stat.size)) / (1024 * 1024);
+    std.debug.print("Size: {d:.1} MB\n\n", .{size_mb});
+
+    // Benchmark 1: Standard sequential read
+    {
+        std.debug.print("1. Standard read()...\n", .{});
+        const start = std.time.nanoTimestamp();
+
+        const f = try std.fs.cwd().openFile(test_file, .{});
+        defer f.close();
+
+        const buffer = try allocator.alloc(u8, stat.size);
+        defer allocator.free(buffer);
+
+        _ = try f.readAll(buffer);
+
+        const elapsed_ns = std.time.nanoTimestamp() - start;
+        const elapsed_s = @as(f64, @floatFromInt(elapsed_ns)) / 1_000_000_000.0;
+        const throughput = size_mb / elapsed_s / 1024.0; // GB/s
+        std.debug.print("   Time: {d:.1}ms, Throughput: {d:.2} GB/s\n\n", .{
+            @as(f64, @floatFromInt(elapsed_ns)) / 1_000_000.0,
+            throughput,
+        });
+    }
+
+    // Benchmark 2: Async Loader
+    {
+        std.debug.print("2. AsyncLoader (mmap + madvise)...\n", .{});
+
+        var loader = try AsyncLoader.init(allocator, test_file);
+        defer loader.deinit();
+
+        const start = std.time.nanoTimestamp();
+        try loader.startPrefetch();
+        try loader.waitReady();
+        const elapsed_ns = std.time.nanoTimestamp() - start;
+
+        const elapsed_s = @as(f64, @floatFromInt(elapsed_ns)) / 1_000_000_000.0;
+        const throughput = size_mb / elapsed_s / 1024.0; // GB/s
+        std.debug.print("   Time: {d:.1}ms, Throughput: {d:.2} GB/s\n", .{
+            @as(f64, @floatFromInt(elapsed_ns)) / 1_000_000.0,
+            throughput,
+        });
+        std.debug.print("   (Internal: {d:.1}ms, {d:.2} GB/s)\n\n", .{
+            loader.getLoadTimeMs(),
+            loader.getThroughputGBs(),
+        });
+    }
+
+    // Benchmark 3: Draft model simulation
+    {
+        std.debug.print("3. Simulated Speculative Decode:\n", .{});
+        std.debug.print("   Starting 'draft model' (300ms sleep) + async prefetch...\n", .{});
+
+        var loader = try AsyncLoader.init(allocator, test_file);
+        defer loader.deinit();
+
+        const start = std.time.nanoTimestamp();
+
+        // Start async prefetch
+        try loader.startPrefetch();
+
+        // Simulate draft model running (this would be actual inference)
+        std.Thread.sleep(300 * std.time.ns_per_ms);
+
+        // Check if prefetch finished during draft
+        const prefetch_ready_during_draft = loader.isReady();
+
+        // Wait for prefetch if not done
+        try loader.waitReady();
+
+        const elapsed_ns = std.time.nanoTimestamp() - start;
+
+        std.debug.print("   Prefetch hidden behind draft: {}\n", .{prefetch_ready_during_draft});
+        std.debug.print("   Total time: {d:.1}ms\n", .{
+            @as(f64, @floatFromInt(elapsed_ns)) / 1_000_000.0,
+        });
+        std.debug.print("   Prefetch time: {d:.1}ms\n", .{loader.getLoadTimeMs()});
+
+        if (prefetch_ready_during_draft) {
+            std.debug.print("   ✅ SSD latency successfully hidden!\n", .{});
+        } else {
+            std.debug.print("   ❌ SSD slower than draft - need longer draft window\n", .{});
+        }
+    }
+
+    std.debug.print("\n=== Benchmark Complete ===\n", .{});
+}
